// Space: O(w * b)

class Solution {
public:
    vector<int> assignBikes(vector<vector<int>>& workers, vector<vector<int>>& bikes) {
        using P = vector<int>;
        vector<vector<P>> distances(workers.size());
        for (int i = 0; i < workers.size(); ++i) {
            for (int j = 0; j < bikes.size(); ++j) {
                distances[i].push_back({manhattan(workers[i], bikes[j]), i, j});
            }
            sort(distances[i].begin(), distances[i].end(), greater<P>());
        }

        vector<int> result(workers.size());
        unordered_set<int> lookup;
        priority_queue<P, vector<P>, greater<P>> min_heap;
        for (int i = 0; i < workers.size(); ++i) {
            min_heap.emplace(distances[i].back());
            distances[i].pop_back();
        }
        while (lookup.size() < workers.size()) {
            const auto worker = min_heap.top()[1];
            const auto bike = min_heap.top()[2];
            min_heap.pop();
            if (!lookup.count(bike)) {
                result[worker] = bike;
                lookup.emplace(bike);
            } else {
                min_heap.emplace(distances[worker].back());
                distances[worker].pop_back();
            }
        }
        return result;
    }

private:
    int manhattan(const vector<int>& p1, const vector<int>& p2) {
        return abs(p1[0] - p2[0]) + abs(p1[1] - p2[1]);
    }
};

# Time:  O((w * b) * log(w * b))
# Space: O(w * b)

import heapq


class Solution(object):
    def assignBikes(self, workers, bikes):
        """
        :type workers: List[List[int]]
        :type bikes: List[List[int]]
        :rtype: List[int]
        """
        def manhattan(p1, p2):
            return abs(p1[0] - p2[0]) + abs(p1[1] - p2[1])

        distances = [[] for _ in xrange(len(workers))]
        for i in xrange(len(workers)):
            for j in xrange(len(bikes)):
                distances[i].append((manhattan(workers[i], bikes[j]), i, j))
            distances[i].sort(reverse = True)

        result = [None] * len(workers)
        lookup = set()
        min_heap = []
        for i in xrange(len(workers)):
            heapq.heappush(min_heap, distances[i].pop())
        while len(lookup) < len(workers):
            _, worker, bike = heapq.heappop(min_heap)
            if bike not in lookup:
                result[worker] = bike
                lookup.add(bike)
            else:
                heapq.heappush(min_heap, distances[worker].pop())
        return result
